/**
 * 爻名映射
 * 根据卦的阴阳属性和爻位生成爻名
 */
export function getYaoMing(guaCode: string): string[] {
  const yaoMing: string[] = [];
  const yaoNames = ['初', '二', '三', '四', '五', '上'];

  for (let i = 5; i >= 0; i--) {
    const isYang = guaCode[i] === '1';
    const name = yaoNames[5 - i] + (isYang ? '九' : '六');
    yaoMing.push(name);
  }

  return yaoMing;
}

/**
 * 爻象映射
 */
export function getYaoXiang(guaCode: string): string[] {
  const yaoXiang: string[] = [];

  for (let i = 5; i >= 0; i--) {
    yaoXiang.push(guaCode[i] === '1' ? '阳爻' : '阴爻');
  }

  return yaoXiang;
}

/**
 * 爻辞映射（简化版，仅提供基础爻辞）
 */
export function getYaoCi(guaMing: string, yaoMing: string[]): string[] {
  // 简化版：返回基础爻辞格式
  return yaoMing.map((name, index) => {
    return `${name}：${guaMing}之${name}爻辞。`;
  });
}

